import React, { useEffect, useState } from "react";
import API from "../../api/api";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";

export default function Earnings() {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get("/proposals/my")
      .then(r => { setProposals(r.data||[]); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const accepted  = proposals.filter(p => p.status === "accepted");
  const pending   = proposals.filter(p => !p.status || p.status === "pending");
  const rejected  = proposals.filter(p => p.status === "rejected");
  const acceptedVal = accepted.reduce((s,p) => s + parseFloat(p.bid||0), 0);
  const pendingVal  = pending.reduce((s,p)  => s + parseFloat(p.bid||0), 0);

  const badge = (s) => {
    const m = { accepted:{bg:"#dcfce7",color:"#15803d"}, rejected:{bg:"#fee2e2",color:"#dc2626"}, pending:{bg:"#fef9c3",color:"#a16207"} };
    return m[s] || m.pending;
  };

  if (loading) return <div style={{ background:"#f8fafc", minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center" }}><span style={{ color:"#0f766e", fontWeight:"600" }}>Loading...</span></div>;

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>
      <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>Earnings Dashboard</h1>
      <p style={{ color:"#64748b", fontSize:"13px", marginBottom:"28px" }}>Track your bids and proposal income</p>

      {/* STAT CARDS */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:"16px", marginBottom:"20px" }}>
        {[
          { label:"Total Earned",     value:"₹0",                                    color:"#16a34a", border:"#16a34a", hint:"No withdrawals yet" },
          { label:"Accepted Value",   value: acceptedVal>0?`₹${acceptedVal.toLocaleString()}`:"₹0", color:"#0891b2", border:"#0891b2", hint:"From accepted bids" },
          { label:"Pending Value",    value: pendingVal>0?`₹${pendingVal.toLocaleString()}`:"₹0",   color:"#d97706", border:"#d97706", hint:"Awaiting decision" },
          { label:"Total Proposals",  value: proposals.length,                       color:"#7c3aed", border:"#7c3aed", hint:"All time" },
        ].map((c,i) => (
          <div key={i} style={{ background:"white", border:"1px solid #e2e8f0", borderTop:`3px solid ${c.border}`, borderRadius:"12px", padding:"20px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
            <p style={{ fontSize:"11px", fontWeight:"700", color:"#94a3b8", textTransform:"uppercase", letterSpacing:"0.8px", margin:"0 0 8px" }}>{c.label}</p>
            <p style={{ fontSize:"24px", fontWeight:"800", color:c.color, margin:"0 0 4px" }}>{c.value}</p>
            <p style={{ fontSize:"11px", color:"#94a3b8", margin:0 }}>{c.hint}</p>
          </div>
        ))}
      </div>

      {/* STATUS BOXES */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:"14px", marginBottom:"24px" }}>
        {[
          { label:"✅ Accepted", count:accepted.length, bg:"#f0fdf4", border:"#bbf7d0", color:"#16a34a" },
          { label:"⏳ Pending",  count:pending.length,  bg:"#fefce8", border:"#fde68a", color:"#d97706" },
          { label:"❌ Rejected", count:rejected.length, bg:"#fff1f2", border:"#fecdd3", color:"#dc2626" },
        ].map((b,i) => (
          <div key={i} style={{ background:b.bg, border:`1px solid ${b.border}`, borderRadius:"12px", padding:"20px", textAlign:"center" }}>
            <p style={{ fontSize:"32px", fontWeight:"800", color:b.color, margin:"0 0 4px" }}>{b.count}</p>
            <p style={{ fontSize:"13px", fontWeight:"600", color:b.color, margin:0 }}>{b.label}</p>
          </div>
        ))}
      </div>

      {/* TABLE */}
      <div style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"14px", overflow:"hidden", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
        <div style={{ padding:"16px 20px", borderBottom:"1px solid #f1f5f9" }}>
          <h2 style={{ fontSize:"14px", fontWeight:"700", color:"#0f172a", margin:0 }}>All Proposals & Earnings</h2>
        </div>
        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:"13px" }}>
          <thead>
            <tr style={{ background:"#f8fafc" }}>
              {["Project","Your Bid","Project Budget","Date","Status"].map(h => (
                <th key={h} style={{ textAlign:"left", padding:"11px 18px", fontSize:"10px", fontWeight:"700", color:"#94a3b8", textTransform:"uppercase", letterSpacing:"0.8px", borderBottom:"1px solid #f1f5f9" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {proposals.length === 0 ? (
              <tr><td colSpan={5} style={{ textAlign:"center", padding:"40px", color:"#94a3b8" }}>No proposals yet</td></tr>
            ) : proposals.map(p => {
              const b = badge(p.status);
              return (
                <tr key={p.id} style={{ borderBottom:"1px solid #f8fafc" }}>
                  <td style={{ padding:"14px 18px", fontWeight:"600", color:"#0f172a" }}>{p.project_title}</td>
                  <td style={{ padding:"14px 18px", fontWeight:"700", color:"#0f766e" }}>₹{p.bid}</td>
                  <td style={{ padding:"14px 18px", color:"#64748b" }}>₹{p.project_budget||"—"}</td>
                  <td style={{ padding:"14px 18px", color:"#94a3b8" }}>{fmt(p.created_at)}</td>
                  <td style={{ padding:"14px 18px" }}>
                    <span style={{ background:b.bg, color:b.color, fontSize:"10px", fontWeight:"700", padding:"3px 10px", borderRadius:"20px", textTransform:"capitalize" }}>
                      {p.status||"pending"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
